// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <time.h>
#include <stdint.h>
#include <stdbool.h>
typedef struct Crane {
    int L, R, K;
} Crane;

int compareCrane(const void *a, const void *b) {
    Crane *c1 = (Crane *)a;
    Crane *c2 = (Crane *)b;
    return c1->R - c2->R;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int *Z = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &Z[i]);
        }
        Crane *cranes = (Crane *)malloc(M * sizeof(Crane));
        for (int i = 0; i < M; i++) {
            scanf("%d %d %d", &cranes[i].L, &cranes[i].R, &cranes[i].K);
        }
        qsort(cranes, M, sizeof(Crane), compareCrane);
        int ans = 0;
        bool possible = true;
        for (int i = 0; i < N; i++) {
            int minBeams = Z[i];
            Crane *bestCrane = NULL;
            for (int j = 0; j < M; j++) {
                if (cranes[j].L <= i + 1 && cranes[j].R >= i + 1 && cranes[j].K >= minBeams) {
                    if (bestCrane == NULL || cranes[j].K < bestCrane->K) {
                        bestCrane = &cranes[j];
                    }
                }
            }
            if (bestCrane == NULL) {
                possible = false;
                break;
            }
            ans += minBeams;
            bestCrane->K -= minBeams;
        }
        if (possible) {
            printf("YES %d\n", ans);
        } else {
            printf("NO\n");
        }
        free(Z);
        free(cranes);
    }
    return 0;
}

