// COMPLETE, COMPILABLE Java code
import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Crane implements Comparable<Crane> {
        int L, R, K;
        public Crane(int L, int R, int K) {
            this.L = L;
            this.R = R;
            this.K = K;
        }
        @Override
        public int compareTo(Crane o) {
            return this.R - o.R;
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[] Z = new int[N];
            for (int i = 0; i < N; i++) {
                Z[i] = sc.nextInt();
            }
            Crane[] cranes = new Crane[M];
            for (int i = 0; i < M; i++) {
                cranes[i] = new Crane(sc.nextInt(), sc.nextInt(), sc.nextInt());
            }
            Arrays.sort(cranes);
            int ans = 0;
            boolean possible = true;
            for (int i = 0; i < N; i++) {
                int minBeams = Z[i];
                Crane bestCrane = null;
                for (int j = 0; j < M; j++) {
                    if (cranes[j].L <= i + 1 && cranes[j].R >= i + 1 && cranes[j].K >= minBeams) {
                        if (bestCrane == null || cranes[j].K < bestCrane.K) {
                            bestCrane = cranes[j];
                        }
                    }
                }
                if (bestCrane == null) {
                    possible = false;
                    break;
                }
                ans += minBeams;
                bestCrane.K -= minBeams;
            }
            if (possible) {
                System.out.println("YES " + ans);
            } else {
                System.out.println("NO");
            }
        }
    }
}

